import{_ as e,o,c as n,ag as i}from"./chunks/framework.R9ZDD-VK.js";const h=JSON.parse('{"title":"Options","description":"","frontmatter":{"title":"Options","order":8},"headers":[],"relativePath":"reference/options.md","filePath":"reference/options.md"}'),l={name:"reference/options.md"};function a(r,t,d,s,g,c){return o(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h1><h2 id="plugin-options-and-googlelogin-component-props" tabindex="-1">Plugin Options and GoogleLogin Component Props <a class="header-anchor" href="#plugin-options-and-googlelogin-component-props" aria-label="Permalink to &quot;Plugin Options and GoogleLogin Component Props&quot;">​</a></h2><p>Options used when <a href="./../guide/getting-started#initialize-the-plugin">initializing the plugin</a> and prop values in the <a href="./../guide/getting-started#using-the-googlelogin-component">GoogleLogin component</a> are similar.</p><table tabindex="0"><thead><tr><th>Name</th><th style="text-align:center;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td>clientId</td><td style="text-align:center;">String</td><td style="text-align:left;">Google API client ID</td></tr><tr><td>prompt</td><td style="text-align:center;">Boolean</td><td style="text-align:left;">Set this to true to display the One Tap prompt<br><br>Setting this value as a prop of the GoogleLogin component will be ignored if this is set as option on plugin initialization</td></tr><tr><td>autoLogin</td><td style="text-align:center;">Boolean</td><td style="text-align:left;">Setting this value to true will make the prompt to automatically log in without any user interactions<br><br>For this to work <code>prompt</code> must be set to true<br><br>Setting this value as a prop of the GoogleLogin component will be ignored if this is set as option on plugin initialization</td></tr><tr><td>popupType</td><td style="text-align:center;">String</td><td style="text-align:left;">Type of callback response, accepts either <code>CODE</code> or <code>TOKEN</code>, this only works if a <a href="./../guide/custom-button#custom-button-as-slot">custom button is added as a slot</a></td></tr><tr><td>callback</td><td style="text-align:center;">Function</td><td style="text-align:left;">The callback function which will be triggered with a response object once the login is completed</td></tr><tr><td>error</td><td style="text-align:center;">Function</td><td style="text-align:left;">An error function which will be triggered on any error encountered while showing the prompts/popups</td></tr><tr><td>idConfiguration</td><td style="text-align:center;">Object</td><td style="text-align:left;">IdConfiguration object for initializing, see list of fields and descriptions of the IdConfiguration <a href="https://developers.google.com/identity/gsi/web/reference/js-reference#IdConfiguration" target="_blank" rel="noreferrer">here</a></td></tr><tr><td>buttonConfig</td><td style="text-align:center;">Object</td><td style="text-align:left;">Configuration of the login button rendered by Google, see list of fields and descriptions <a href="https://developers.google.com/identity/gsi/web/reference/js-reference#GsiButtonConfiguration" target="_blank" rel="noreferrer">here</a></td></tr></tbody></table><h2 id="function-googleonetap" tabindex="-1">Function googleOneTap <a class="header-anchor" href="#function-googleonetap" aria-label="Permalink to &quot;Function googleOneTap&quot;">​</a></h2><p><code>googleOneTap</code> function accepts the following options:</p><table tabindex="0"><thead><tr><th>Name</th><th style="text-align:center;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td>clientId</td><td style="text-align:center;">String</td><td style="text-align:left;">Google API client ID</td></tr><tr><td>context</td><td style="text-align:center;">String</td><td style="text-align:left;">The title and words in the One Tap prompt, this can be <code>signin</code>|<code>signup</code>|<code>use</code> see <a href="https://developers.google.com/identity/gsi/web/guides/change-sign-in-context" target="_blank" rel="noreferrer">here</a> for more info</td></tr><tr><td>autoLogin</td><td style="text-align:center;">Boolean</td><td style="text-align:left;">Set this to true if you want the one-tap prompt to automatically login</td></tr><tr><td>cancelOnTapOutside</td><td style="text-align:center;">Boolean</td><td style="text-align:left;">Controls whether to cancel the prompt if the user clicks outside of the prompt</td></tr></tbody></table><h2 id="function-googleauthcodelogin-and-googletokenlogin" tabindex="-1">Function googleAuthCodeLogin and googleTokenLogin <a class="header-anchor" href="#function-googleauthcodelogin-and-googletokenlogin" aria-label="Permalink to &quot;Function googleAuthCodeLogin and googleTokenLogin&quot;">​</a></h2><p><code>googleAuthCodeLogin</code> and <code>googleTokenLogin</code> functions accept an object with a client id. This is useful if you are not planning to initialize the plugin in <code>main.js</code>:</p><table tabindex="0"><thead><tr><th>Name</th><th style="text-align:center;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td>clientId</td><td style="text-align:center;">String</td><td style="text-align:left;">Google API client ID</td></tr></tbody></table>',10)])])}const u=e(l,[["render",a]]);export{h as __pageData,u as default};
